import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Check } from 'lucide-react';
import { useQuiz } from '../../state/QuizContext';
import { FadeUp, StaggerContainer, StaggerItem } from '../animations';
import { WEBINAR_INCLUDES, TESTIMONIALS } from '../../data/content';
import { getIdentityOpener, getZoneMessage, formatTime } from '../../utils';

export function PricingScreen() {
  const { state, back, progress } = useQuiz();
  const [secs, setSecs] = useState(1199);

  useEffect(() => {
    const t = setInterval(() => setSecs((s) => Math.max(0, s - 1)), 1000);
    return () => clearInterval(t);
  }, []);

  const identityOpener = getIdentityOpener(state.single.q_identity);
  const zoneMsg = getZoneMessage(state.single.q_zone);

  const handleBuyMain = () => alert('Redirecting to Razorpay — ₹1,098');
  const handleBuyEntry = () => alert('Redirecting to Razorpay — ₹99');

  return (
    <div className="bg-cream-50 min-h-[90vh] px-5 py-6 pb-10">
      <TopBar percent={progress} onBack={back} />
      {/* Countdown */}
      <FadeUp delay={0.02}>
        <div className="bg-amber-400/15 border border-amber-400/30 rounded-xl py-2.5 px-4 flex items-center justify-center gap-2 mb-4">
          <span className="text-sm text-amber-700">⏰ This offer expires in:</span>
          <span className="font-bold text-amber-700 text-sm">{formatTime(secs)}</span>
        </div>
      </FadeUp>

      {/* Personalized opener */}
      <FadeUp delay={0.08}>
        <div className="bg-teal-50 border-l-4 border-teal-400 rounded-r-2xl p-4 mb-5">
          <p className="text-sm text-teal-800 leading-relaxed">
            <strong>{identityOpener}</strong>, your body is primarily storing{' '}
            <strong>{zoneMsg}</strong>. The Breath Chakra Reset workshop is a live 2.5-hour session where Dr. Valar guides you through releasing exactly this.
          </p>
        </div>
      </FadeUp>

      {/* MAIN OFFER */}
      <FadeUp delay={0.14}>
        <div className="relative border-2 border-teal-400 rounded-2xl p-5 mb-3 bg-teal-50 overflow-visible">
          {/* Recommended badge */}
          <div className="absolute -top-3 left-1/2 -translate-x-1/2">
            <span className="bg-teal-500 text-white text-xs font-bold px-4 py-1 rounded-full whitespace-nowrap shadow">
              ⭐ RECOMMENDED FOR YOUR PROFILE
            </span>
          </div>

          <div className="mt-2 mb-3">
            <p className="font-serif text-lg font-semibold text-teal-800">Workshop + Nervous System SOS Kit</p>
            <p className="text-xs text-teal-600">The complete reset — live session + everything to continue at home</p>
          </div>

          {/* Price */}
          <div className="flex items-baseline gap-2 mb-4">
            <span className="font-serif text-4xl font-bold text-teal-800">₹1,098</span>
            <span className="text-xs text-slate-500">₹99 workshop + ₹999 SOS kit</span>
          </div>

          {/* Includes list */}
          <div className="bg-white/70 rounded-xl p-3 mb-4">
            <p className="text-xs font-bold text-teal-800 uppercase tracking-wide mb-2">WHAT YOU GET:</p>
            <StaggerContainer delayStart={0} stagger={0.05}>
              {WEBINAR_INCLUDES.map((item) => (
                <StaggerItem key={item.text}>
                  <div className="flex items-center gap-2 mb-1.5">
                    <span className="text-base">{item.icon}</span>
                    <span className="text-xs text-teal-800">{item.text}</span>
                  </div>
                </StaggerItem>
              ))}
            </StaggerContainer>
          </div>

          {/* CTA */}
          <motion.button
            onClick={handleBuyMain}
            className="w-full py-4 rounded-xl text-white text-base font-bold font-sans shadow-lg"
            style={{ background: 'linear-gradient(135deg, #E8A830, #D4772C)' }}
            whileTap={{ scale: 0.98 }}
            whileHover={{ y: -2, boxShadow: '0 12px 30px rgba(212,119,44,0.45)' }}
            animate={{
              boxShadow: ['0 0 0 0 rgba(232,168,48,0)', '0 0 22px 5px rgba(232,168,48,0.3)', '0 0 0 0 rgba(232,168,48,0)'],
            }}
            transition={{ boxShadow: { duration: 2.5, repeat: Infinity } }}
          >
            Get Workshop + SOS Kit — ₹1,098 →
          </motion.button>
        </div>
      </FadeUp>

      {/* Testimonials */}
      <div className="mb-4">
        <p className="text-xs font-semibold text-slate-400 text-center uppercase tracking-wider mb-3">People who took this step</p>
        {TESTIMONIALS.slice(0, 2).map((t, i) => (
          <FadeUp key={t.author} delay={0.3 + i * 0.1}>
            <div className="bg-white border border-teal-100 rounded-xl p-3.5 mb-2 shadow-sm">
              <p className="text-xs text-slate-600 italic leading-relaxed mb-2">"{t.quote}"</p>
              <p className="text-xs font-semibold text-slate-500">— {t.author}, {t.location}</p>
            </div>
          </FadeUp>
        ))}
      </div>

      {/* DOWNSELL */}
      <FadeUp delay={0.45}>
        <div className="border border-slate-200 rounded-2xl p-4 mb-4 bg-white">
          <p className="font-semibold text-slate-700 text-sm mb-1">Live Workshop Only</p>
          <p className="text-xs text-slate-400 mb-3">Start with the live session — feel the shift first</p>
          <span className="font-serif text-3xl font-bold text-slate-700">₹99</span>
          <div className="mt-3 mb-3">
            {['2.5-hour live session with Dr. Valar', 'Real-time nervous system shift experience'].map((f) => (
              <div key={f} className="flex items-center gap-1.5 mb-1">
                <Check size={12} className="text-teal-400 flex-shrink-0" />
                <span className="text-xs text-slate-600">{f}</span>
              </div>
            ))}
          </div>
          <button
            onClick={handleBuyEntry}
            className="w-full py-2.5 rounded-xl border border-teal-300 text-teal-600 text-sm font-semibold font-sans hover:bg-teal-50 transition-colors"
          >
            Just the workshop for now — ₹99
          </button>
        </div>
      </FadeUp>

      {/* Footer */}
      <FadeUp delay={0.55}>
        <p className="text-xs text-slate-400 text-center leading-relaxed">
          Secure checkout via Razorpay · One-time payment · No subscriptions
        </p>
      </FadeUp>
    </div>
  );
}
